--
-- Table structure for table `builder_products`
--

CREATE TABLE `builder_products` (
  `id` bigint UNSIGNED NOT NULL,
  `name` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `brand` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `component_type` enum('cpu','gpu','motherboard','ram','case','cpu_cooler','case_fan','storage','psu') COLLATE utf8mb4_unicode_ci NOT NULL,
  `image` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `axon_product_slug` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `amazon_url` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `price` decimal(10,2) NOT NULL DEFAULT '0.00',
  `discount_price` decimal(10,2) NOT NULL DEFAULT '0.00',
  `in_stock` tinyint(1) NOT NULL DEFAULT '1',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `socket` varchar(20) COLLATE utf8mb4_unicode_ci GENERATED ALWAYS AS (json_unquote(json_extract(`specs`,_utf8mb4'$.socket'))) STORED,
  `tdp` smallint UNSIGNED GENERATED ALWAYS AS (cast(json_unquote(json_extract(`specs`,_utf8mb4'$.tdp')) as unsigned)) STORED,
  `psu_wattage` smallint UNSIGNED GENERATED ALWAYS AS (cast(json_unquote(json_extract(`specs`,_utf8mb4'$.wattage')) as unsigned)) STORED,
  `ram_type` varchar(10) COLLATE utf8mb4_unicode_ci GENERATED ALWAYS AS (json_unquote(json_extract(`specs`,_utf8mb4'$.ram_type'))) STORED,
  `form_factor` varchar(20) COLLATE utf8mb4_unicode_ci GENERATED ALWAYS AS (json_unquote(json_extract(`specs`,_utf8mb4'$.form_factor'))) STORED,
  `perf_score` smallint UNSIGNED NOT NULL DEFAULT '0' COMMENT 'Generički score 0-1000 za kompatibilnost i sorting',
  `tdmark_base` smallint UNSIGNED NOT NULL DEFAULT '0' COMMENT '3DMark Time Spy bazni score (GPU-specific)',
  `fps_base_1080` smallint UNSIGNED NOT NULL DEFAULT '0' COMMENT 'Bazni FPS na 1080p za GPU (0 za ne-GPU komponente)',
  `specs` json DEFAULT NULL,
  `short_desc` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

